/*
This is an alternate targeting method for use with DiceSoNice and the PFU Combat HUD which mimics the targeting behavior of certain early jRPGs such as Final Fantasy (NES).
This behavior flips a coin for each party member until a 2 is flipped, then targets that player.
Players can change how likely they are to be hit by requesting to be reordered in the Combat HUD.
@author Zeyami
*/


// Will get a list of only friendly tokens in order they show up on the combat HUD. Erika of ProjectFU wrote this section.
const party = game.settings
  .get("projectfu", "optionCombatHudActorOrdering")
  .filter(({ tokenId }) => {
      const partymember = game.combat.combatants.find((partymember) => partymember.tokenId === tokenId)
      if (partymember?.faction === "friendly") return true;
      return false;
  })
  .sort((a, b) => a.order - b.order)
  .map(({ tokenId }) => game.combat.combatants.find((partymember) => partymember.tokenId === tokenId).token);

//Determines the # of coins to flip in DiceSoNice as well as which party member to target.
let roll;
let i = -1;
do {
  roll = Math.ceil(Math.random() * 1000);
  i += 1;
} while ((roll <= 500) && (i + 1 <= party.length));

//Sends the results to DiceSoNice for visualization.
let iRoll = await new Roll(i+'d2').evaluate({minimize: true});
game.dice3d.showForRoll(iRoll);
let tRoll = await new Roll('1d2').evaluate({maximize: true});
game.dice3d.showForRoll(tRoll);

//Finds the matching token on the canvas and targets it.
const token = canvas.tokens.placeables.find(t => t.document.name === party[i].name);
token.setTarget(true, { user: game.user, ReleaseOthers: true });
